import React from "react"
import Layout from "../components/Layout"
import DealCard from "../components/DealCard"
import dealsData from "../../data/deals.json"
import { Link } from "gatsby"

const categoryIcons = {
  vps: "🖥️", gpu: "🎮", domain: "🌐", storage: "💾", serverless: "⚡", "ai-api": "🧠"
}

const categoryLabels = {
  vps: "Virtual Private Servers",
  gpu: "GPU & Compute",
  domain: "Domains & DNS",
  storage: "Object Storage",
  serverless: "Serverless & Edge",
  "ai-api": "AI APIs & Models",
}

const CategoriesPage = () => {
  const { deals } = dealsData
  const categories = [...new Set(deals.map(d => d.category))]

  return (
    <Layout activeNav="categories">
      <div className="page-header">
        <h1>Categories</h1>
        <p className="page-subtitle">Browse deals by resource type</p>
      </div>

      {categories.map(cat => {
        const catDeals = deals.filter(d => d.category === cat)
        const cheapest = catDeals.sort((a, b) => {
          const pa = a.price.monthly || a.price.hourly || a.price.monthlyPerGB || 9999
          const pb = b.price.monthly || b.price.hourly || b.price.monthlyPerGB || 9999
          return pa - pb
        })[0]

        return (
          <section key={cat} className="section">
            <div className="data-panel">
              <div className="panel-header">
                <span className="panel-title">
                  {categoryIcons[cat] || "📦"} {categoryLabels[cat] || cat.replace("-", " ")}
                </span>
                <span className="panel-title" style={{ color: "var(--text-muted)", fontWeight: 400, fontSize: "0.7rem" }}>
                  {catDeals.length} deal{catDeals.length !== 1 ? "s" : ""}
                </span>
              </div>
              <div className="panel-body" style={{ padding: "0" }}>
                {catDeals.slice(0, 6).map(d => (
                  <div key={d.id} style={{
                    display: "flex", justifyContent: "space-between", alignItems: "center",
                    padding: "0.5rem 1rem", borderBottom: "1px solid var(--border-color)",
                  }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                      <span style={{ color: "var(--text-muted)", fontSize: "0.75rem" }}>{d.provider}</span>
                      <span style={{ color: "var(--text-primary)", fontSize: "0.85rem", fontWeight: 600 }}>{d.name}</span>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: "0.5rem" }}>
                      <span style={{ color: "var(--green)", fontFamily: "var(--font-mono)", fontSize: "0.85rem", fontWeight: 700 }}>
                        ${d.price.monthly || d.price.hourly || d.price.monthlyPerGB || d.price.inputPer1M || "—"}
                        <span style={{ fontSize: "0.7rem", color: "var(--text-muted)", fontWeight: 400 }}>
                          {d.price.monthly ? "/mo" : d.price.hourly ? "/hr" : d.price.monthlyPerGB ? "/GB" : d.price.inputPer1M ? "/1M" : ""}
                        </span>
                      </span>
                    </div>
                  </div>
                ))}
                {catDeals.length > 6 && (
                  <div style={{ padding: "0.5rem 1rem", textAlign: "center" }}>
                    <Link to={`/deals/?category=${cat}`} style={{
                      fontFamily: "var(--font-mono)", fontSize: "0.75rem", color: "var(--accent-primary)",
                    }}>
                      View all {catDeals.length} {cat.replace("-", " ")} deals →
                    </Link>
                  </div>
                )}
              </div>
            </div>
          </section>
        )
      })}
    </Layout>
  )
}

export const Head = () => (
  <>
    <title>Categories — DevBundles</title>
    <meta name="description" content="Browse deals by category — VPS, GPU, domains, storage, serverless, and AI APIs." />
  </>
)

export default CategoriesPage
